components.css:
article.card {
  padding: var(--a-space-lg);
  background: var(--a-surface-base);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
  transition: all var(--a-transition-base);
}

article.card:hover {
  border-color: var(--a-primary);
  box-shadow: 0 4px 12px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

article.card-image {
  overflow: hidden;
  border-radius: var(--a-radius-lg);
  border: 1px solid var(--a-border);
}

article.card-image img {
  width: 100%;
  height: auto;
  display: block;
}

article.card-image h3,
article.card-image p {
  padding-left: var(--a-space-lg);
  padding-right: var(--a-space-lg);
}

article.card-image h3 {
  margin-top: var(--a-space-lg);
}

article.card-image p {
  margin-bottom: var(--a-space-lg);
}

article.card-highlighted {
  padding: var(--a-space-lg);
  background: var(--a-surface-base);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
  border-left: 4px solid var(--a-primary);
}

article.card-minimal {
  padding: var(--a-space-lg);
  background: var(--a-surface-overlay);
  border-radius: var(--a-radius-md);
}

a.card-interactive {
  display: block;
  padding: var(--a-space-lg);
  background: var(--a-surface-base);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
  text-decoration: none;
  color: inherit;
  transition: all var(--a-transition-base);
  cursor: pointer;
}

a.card-interactive:hover {
  transform: translateY(-4px);
  border-color: var(--a-primary);
  box-shadow: 0 8px 16px color-mix(in oklch, var(--a-primary) 20%, transparent);
}

article.card-with-footer {
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
  overflow: hidden;
}

article.card-with-footer > * {
  padding: 0 var(--a-space-lg);
}

article.card-with-footer h3 {
  padding-top: var(--a-space-lg);
  padding-bottom: 0;
}

article.card-with-footer > p {
  padding-bottom: 0;
}

article.card-with-footer footer {
  padding: var(--a-space-md) var(--a-space-lg);
  background: var(--a-surface-overlay);
  border-top: 1px solid var(--a-border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: var(--a-space-md);
}

section.card-grid {
  display: grid;
  gap: var(--a-space-lg);
  grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
}

@media (max-width: 768px) {
  section.card-grid {
    grid-template-columns: 1fr;
  }
}

article.card-badge {
  position: relative;
  padding: var(--a-space-lg);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
}

span.badge {
  position: absolute;
  top: var(--a-space-md);
  right: var(--a-space-md);
  padding: var(--a-space-xs) var(--a-space-sm);
  background: var(--a-primary);
  color: var(--a-surface-base);
  border-radius: var(--a-radius-sm);
  font-size: var(--a-text-xs);
  font-weight: var(--a-font-weight-semibold);
}

article.card-skeleton {
  padding: var(--a-space-lg);
  border: 1px solid var(--a-border);
  border-radius: var(--a-radius-lg);
}

.skeleton-line {
  height: 1em;
  background: linear-gradient(
    90deg,
    var(--a-surface-overlay) 25%,
    var(--a-surface-base) 50%,
    var(--a-surface-overlay) 75%
  );
  border-radius: var(--a-radius-sm);
  margin-bottom: var(--a-space-md);
  animation: pulse 2s ease-in-out infinite;
}

.skeleton-line-short {
  width: 60%;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
}
